import { S } from '../state.js';
import { doLogin, getColabs } from '../services/auth.js';

export function renderLogin(){
  const hasBackendToken = !!localStorage.getItem('fv_backend_token');
  const colabs = getColabs().filter(c=>c.active!==false && c.senha);
  return`
<div class="auth-wrap">
<div class="auth-card">
  <div class="auth-logo">
    <img src="data:image/png;base64," alt="Laços Eternos" style="width:200px;height:200px;object-fit:contain;filter:drop-shadow(0 4px 20px rgba(200,115,106,.4));"/>
    <span class="sub" style="margin-top:4px;">Sistema de Gestão</span>
  </div>

  ${S.loading
    ? `<div style="text-align:center;padding:30px"><div class="spin"></div><div style="margin-top:12px;font-size:12px;color:var(--muted)">Entrando...</div></div>`
    : `
  <div class="fg">
    <label class="fl">E-mail</label>
    <input class="fi" id="li-email" type="email" placeholder="seu@email.com" autocomplete="username"/>
  </div>
  <div class="fg">
    <label class="fl">Senha</label>
    <input class="fi" id="li-pass" type="password" placeholder="••••••" autocomplete="current-password"/>
  </div>
  <button class="btn btn-primary" id="btn-login"
    style="width:100%;justify-content:center;padding:13px;font-size:15px;margin-top:6px;border-radius:12px;">
    Entrar
  </button>

  ${colabs.length > 0 ? `
  <div style="margin-top:16px;padding:12px;background:var(--cream);border-radius:var(--r);">
    <div style="font-size:10px;font-weight:700;color:var(--muted);text-transform:uppercase;letter-spacing:1px;margin-bottom:8px;">
      👥 Colaboradores cadastrados
    </div>
    ${colabs.slice(0,5).map(c=>`
    <div style="display:flex;align-items:center;justify-content:space-between;padding:6px 8px;
      background:#fff;border-radius:8px;margin-bottom:4px;cursor:pointer;border:1px solid var(--border);"
      onclick="document.getElementById('li-email').value='${c.email}';document.getElementById('li-pass').focus();">
      <div>
        <div style="font-size:12px;font-weight:600">${c.name} <span style="font-size:10px;color:var(--muted)">(${c.cargo})</span></div>
        <div style="font-size:10px;color:var(--muted)">${c.email}</div>
      </div>
      <span style="font-size:10px;background:var(--rose-l);color:var(--rose);padding:2px 6px;border-radius:10px;">Clicar</span>
    </div>`).join('')}
    <div style="font-size:10px;color:var(--muted);margin-top:6px;text-align:center;">
      Clique no nome para preencher o e-mail automaticamente
    </div>
  </div>` : ''}


  ${!hasBackendToken ? `
  <div style="margin-top:10px;padding:10px 12px;background:#FFFBEB;border:1px solid #FCD34D;border-radius:8px;font-size:11px;color:#92400E;">
    ⚠️ <strong>Primeira vez neste dispositivo?</strong> O Administrador deve fazer login primeiro para ativar o sistema.
  </div>` : ''}

  <div style="margin-top:10px;text-align:center;">
    <button id="btn-clear-cache" type="button" style="background:none;border:none;font-size:11px;color:#94A3B8;cursor:pointer;text-decoration:underline;">
      🧹 Limpar cache e recarregar (resolve problemas de acesso)
    </button>
  </div>

  ${S._loginMsg ? `
  <div style="margin-top:14px;padding:14px 16px;background:linear-gradient(135deg,#FDF4F7,#FDE8EF);border:1.5px solid #F4A7B9;border-radius:12px;text-align:center;">
    <div style="font-size:22px;margin-bottom:6px;display:inline-block;animation:spin 2s linear infinite;">🌸</div>
    <div style="font-size:13px;font-weight:600;color:#8B2252;">${S._loginMsg}</div>
    <div style="font-size:11px;color:#C8436A;margin-top:4px;">Por favor, não feche esta tela</div>
  </div>` : ''}`}
</div></div>`;}

export function bindLogin(){
  document.getElementById('btn-login')?.addEventListener('click',()=>{
    doLogin(document.getElementById('li-email').value, document.getElementById('li-pass').value);
  });
  document.getElementById('li-pass')?.addEventListener('keydown',e=>{if(e.key==='Enter')document.getElementById('btn-login').click();});
  document.getElementById('btn-clear-cache')?.addEventListener('click',()=>{
    if(confirm('Isso vai limpar todos os dados salvos neste dispositivo e recarregar a página. Continuar?')){
      try{ localStorage.clear(); sessionStorage.clear(); }catch(e){}
      location.reload();
    }
  });
}
